def is_valid_parentheses(s):
    stack = []
    mapping = {')': '(', '}': '{', ']': '['}

    for char in s:
        if char in mapping.values():
            # If the character is an opening bracket, push it onto the stack
            stack.append(char)
        elif char in mapping.keys():
            # If the character is a closing bracket, check if the top of the stack matches
            if not stack or mapping[char] != stack.pop():
                return False

    # If we've made it this far and the stack is empty, then every opening bracket was matched correctly
    return not stack

def is_palindrome(s):
    s = ''.join(c for c in s if c.isalnum()).lower()
    return s == s[::-1]

def parse_nested_parens(s):
    max_depth = current_depth = 0
    for char in s:
        if char == '(':
            current_depth += 1
            max_depth = max(max_depth, current_depth)
        elif char == ')':
            current_depth -= 1
    return max_depth

def sort_by_frequency(lst):
    # Create a dictionary to store the frequency of each number
    freq = {}
    for num in lst:
        if num in freq:
            freq[num] += 1
        else:
            freq[num] = 1

    # Sort the list based on the frequency and then by value
    return sorted(lst, key=lambda x: (freq[x], x))
